#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1000005,mod=1e9+7;
int n,t,nxt[N],ans[N];
string s;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>t;
	while(t--)
	{
		cin>>s;
		n=s.size();
		memset(nxt,0,sizeof(nxt));
		ans[0]=0,ans[1]=1;
		for(int i=1,j=0;i<n;i++)
		{
			while(j&&(s[i]!=s[j])) j=nxt[j];
			if(s[i]==s[j]) j++;
			nxt[i+1]=j;
			ans[i+1]=ans[j]+1;
		}
		ll cnt=1;
		for(int i=1,j=0;i<n;i++)
		{
			while(j&&(s[i]!=s[j])) j=nxt[j];
			if(s[i]==s[j]) j++;
			while((j*2)>(i+1)) j=nxt[j];
			cnt=cnt*((ll)ans[j]+1)%mod;
		}
		cout<<cnt<<"\n";
	}
	return 0;
}
